import { gs } from '@servicenow/glide';
export function preventStatusRegression(current, previous) {
    const statusOrder = {
        'new': 0,
        'pending_approval': 1,
        'approved': 2,
        'in_progress': 3,
        'completed': 4,
        'rejected': 5
    };
    const currentStatus = current.getValue('status');
    const previousStatus = previous.getValue('status');
    // Allow any transition to "rejected" from any state
    if (currentStatus === 'rejected') {
        return;
    }
    const currentOrder = statusOrder[currentStatus] ?? -1;
    const previousOrder = statusOrder[previousStatus] ?? -1;
    // Prevent moving backwards (except to rejected)
    if (currentOrder < previousOrder && previousStatus !== 'rejected') {
        gs.addErrorMessage('Cannot revert status from "' + previousStatus + '" to "' + currentStatus + '". Status can only move forward.');
        current.setAbortAction(true);
    }
}
